    int magicalString(int n) {
        if (n <= 0) return 0;
        if (n <= 3) return 1;
        string s = "122";
        int res = 1, i = 2, cnt = 2;
        while (cnt < n) {
            int num = s[i++] - '0';
            for (int j = 0; j < num; j++) {
                s += (cnt < n) ? "12"[cnt % 2] : "";
                cnt++;
